-- ---------------------------------------------------------------------------
-- 2b. Case-fold headlines.tags so REPLACE matches every alias FIND_IN_SET
--     sees. BINARY makes the inequality byte-exact (the column's default
--     collation would treat 'IIT' and 'iit' as equal and skip the update).
--     Re-runs are no-ops because tags is already lowercase after the first
--     successful apply.
-- ---------------------------------------------------------------------------
UPDATE headlines
   SET tags = LOWER(tags)
 WHERE tags IS NOT NULL
   AND BINARY tags <> BINARY LOWER(tags);

-- ---------------------------------------------------------------------------
-- 3. Rewrite tags. Two UPDATEs per non-trivial alias (alias != canonical):
--    (a) BOTH alias and canonical present -> delete the alias (dedup).
--    (b) Only the alias is present -> REPLACE alias with canonical.
--    Comma-anchored everywhere so 'kv-cache' never matches 'mega-kv-cache-x'.
--    Both are FIND_IN_SET-guarded so they are independently no-ops on re-run.
-- ---------------------------------------------------------------------------
-- adaptive -> memory-systems
UPDATE headlines
   SET tags = TRIM(BOTH ',' FROM
               REPLACE(
                 REPLACE(CONCAT(',', tags, ','), ',adaptive,', ','),
                 ',,', ','))
 WHERE tags IS NOT NULL
   AND FIND_IN_SET('adaptive', tags)
   AND FIND_IN_SET('memory-systems', tags);
UPDATE headlines
   SET tags = TRIM(BOTH ',' FROM REPLACE(CONCAT(',', tags, ','), ',adaptive,', ',memory-systems,'))
 WHERE tags IS NOT NULL
   AND FIND_IN_SET('adaptive', tags)
   AND NOT FIND_IN_SET('memory-systems', tags);
