               REPLACE(
                 REPLACE(CONCAT(',', tags, ','), ',genetic-circuits,', ','),
                 ',,', ','))
 WHERE tags IS NOT NULL
   AND FIND_IN_SET('genetic-circuits', tags)
   AND FIND_IN_SET('synthetic-biology', tags);
