   SET tags = TRIM(BOTH ',' FROM REPLACE(CONCAT(',', tags, ','), ',genetic-circuits,', ',synthetic-biology,'))
 WHERE tags IS NOT NULL
   AND FIND_IN_SET('genetic-circuits', tags)
   AND NOT FIND_IN_SET('synthetic-biology', tags);
